Small feature. `startSseServer(taskStore)` always binds the port from `SSE_PORT` (env). Add an optional `port` parameter (and `host`), defaulting to the current env-derived values, so tests can pass an ephemeral port (`0`). Existing callers (which call it with just `taskStore`) MUST be unaffected. Do not change anything else.

```ts
const SSE_PORT = parseInt(process.env["SSE_PORT"] ?? "3001", 10);
export function startSseServer(taskStore: TaskStore): http.Server {
    const server = http.createServer((req, res) => { /* …unchanged… */ });
    const SSE_HOST = process.env["SSE_HOST"] ?? "127.0.0.1";
    server.listen(SSE_PORT, SSE_HOST, () => {
        logger.info({ host: SSE_HOST, port: SSE_PORT }, "SSE server listening");
    });
    return server;
}
```
